template <typename T, unsigned int compute_iterations, unsigned int static_chunk_size>
__global__ void bench_kernel(const T* src, T* global_sum, size_t num_chunks) {
  const size_t chunk_id = static_cast<size_t>(blockIdx.x);
  if (chunk_id >= num_chunks) return;

  const size_t base = chunk_id * static_chunk_size;

  const T f0 = src[base + 0];
  const T f1 = src[base + 1];
  const T f2 = src[base + 2];
  const T f3 = src[base + 3];
  const T f4 = src[base + 4];
  const T f5 = src[base + 5];
  const T f6 = src[base + 6];
  const T f7 = src[base + 7];

  T local_sum = 0;
  for (size_t i = static_cast<size_t>(threadIdx.x); i < static_chunk_size; i += blockDim.x) {
    T d = src[base + i];

    T t0 = d, t1 = d, t2 = d, t3 = d;
    T t4 = d, t5 = d, t6 = d, t7 = d;

#pragma unroll
    for (size_t j = 0; j < compute_iterations / 8; ++j) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if constexpr (0 < compute_iterations % 8) t0 = t0 * t0 + f0;
    if constexpr (1 < compute_iterations % 8) t1 = t1 * t1 + f1;
    if constexpr (2 < compute_iterations % 8) t2 = t2 * t2 + f2;
    if constexpr (3 < compute_iterations % 8) t3 = t3 * t3 + f3;
    if constexpr (4 < compute_iterations % 8) t4 = t4 * t4 + f4;
    if constexpr (5 < compute_iterations % 8) t5 = t5 * t5 + f5;
    if constexpr (6 < compute_iterations % 8) t6 = t6 * t6 + f6;

    local_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }

  extern __shared__ unsigned char smem_raw[];
  T* smem = reinterpret_cast<T*>(smem_raw);
  smem[threadIdx.x] = local_sum;
  __syncthreads();

  for (unsigned int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      smem[threadIdx.x] += smem[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    atomicAdd(global_sum, smem[0]);
  }
}

template <typename T>
__global__ void write_back_first(T* dst, const T* value) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    dst[0] = value[0];
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element /*seed1*/, const Element /*seed2*/, Element* d_src,
             Element* d_sum) {
  constexpr size_t static_chunk_size = 4096;
  const size_t num_chunks = (len + static_chunk_size - 1) / static_chunk_size;

  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  constexpr int threads = 256;
  bench_kernel<Element, compute_iterations, static_chunk_size>
      <<<static_cast<unsigned int>(num_chunks), threads, threads * sizeof(Element)>>>(d_src, d_sum,
                                                                                       num_chunks);
  CUDA_SAFE_CALL(cudaGetLastError());

  write_back_first<Element><<<1, 1>>>(d_src, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  return len;
}

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, start, stop));

  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return static_cast<double>(ms);
}

template <typename Op>
double benchmark_gpu(Op op, bool do_half_thread_phase) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<decltype(duration)> measurements;
  measurements.reserve((total_runs - 1) + (do_half_thread_phase ? (total_half_thread_runs - 1) : 0));

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (do_half_thread_phase) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t ms, int ci) : memory_space_{ms}, compute_iterations_{ci} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
double runbench_warmup(void* d_buf, size_t size_bytes, double* d_sum_double) {
  const int item_1 = static_cast<int>(size_bytes / sizeof(double));
  auto* ptr = reinterpret_cast<double*>(d_buf);
  return measure_operation([&] { bench<double, compute_iterations>(item_1, 1.0, -1.0, ptr, d_sum_double); });
}

template <unsigned int compute_iterations>
void runbench(void* d_buf, size_t size_bytes, bool do_half_thread_phase, float* d_sum_float,
              double* d_sum_double, int* d_sum_int) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(d_buf);
  auto kernel_time_mad_sp = benchmark_gpu(
      [&] {
        return measure_operation([&] {
          bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float,
                                           d_sum_float);
        });
      },
      do_half_thread_phase);

  double* c_as_double = reinterpret_cast<double*>(d_buf);
  auto kernel_time_mad_dp = benchmark_gpu(
      [&] {
        return measure_operation([&] {
          bench<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double,
                                            d_sum_double);
        });
      },
      do_half_thread_phase);

  int* c_as_int = reinterpret_cast<int*>(d_buf);
  auto kernel_time_mad_int = benchmark_gpu(
      [&] {
        return measure_operation([&] {
          bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int, d_sum_int);
        });
      },
      do_half_thread_phase);

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations << ",   "
            << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) / static_cast<double>(memory_traffic) << ","
            << setw(8) << setprecision(2) << kernel_time_mad_sp << "," << setw(8)
            << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) / static_cast<double>(memory_traffic) << ","
            << setw(8) << setprecision(2) << kernel_time_mad_dp << "," << setw(8)
            << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) / static_cast<double>(memory_traffic) << ","
            << setw(8) << setprecision(2) << kernel_time_mad_int << "," << setw(8)
            << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int * 1000. /
                   (1000. * 1000. * 1000.)
            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* d_buf, size_t size_bytes, bool do_half_thread_phase, float* d_sum_float,
                    double* d_sum_double, int* d_sum_int) {
  runbench<compute_iterations>(d_buf, size_bytes, do_half_thread_phase, d_sum_float, d_sum_double,
                               d_sum_int);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* d_buf, size_t size_bytes, bool do_half_thread_phase, float* d_sum_float,
                    double* d_sum_double, int* d_sum_int) {
  runbench_range<j1>(d_buf, size_bytes, do_half_thread_phase, d_sum_float, d_sum_double, d_sum_int);
  runbench_range<j2, Args...>(d_buf, size_bytes, do_half_thread_phase, d_sum_float, d_sum_double,
                              d_sum_int);
}

extern "C" void mixbenchGPU(double* c, long size) {
  const size_t size_bytes = static_cast<size_t>(size) * sizeof(double);

  void* d_buf = nullptr;
  float* d_sum_float = nullptr;
  double* d_sum_double = nullptr;
  int* d_sum_int = nullptr;

  CUDA_SAFE_CALL(cudaMalloc(&d_buf, size_bytes));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_float, sizeof(float)));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_double, sizeof(double)));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_int, sizeof(int)));

  CUDA_SAFE_CALL(cudaMemset(d_buf, 0, size_bytes));

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup<16>(d_buf, size_bytes, d_sum_double);

  cudaDeviceProp prop{};
  int dev = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&dev));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, dev));
  const bool do_half_thread_phase = (prop.multiProcessorCount > 1);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8, 8 * 8, 10 * 8,
                 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8, 40 * 8, 64 * 8>(
      d_buf, size_bytes, do_half_thread_phase, d_sum_float, d_sum_double, d_sum_int);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  CUDA_SAFE_CALL(cudaMemcpy(c, d_buf, sizeof(double), cudaMemcpyDeviceToHost));

  CUDA_SAFE_CALL(cudaFree(d_sum_int));
  CUDA_SAFE_CALL(cudaFree(d_sum_double));
  CUDA_SAFE_CALL(cudaFree(d_sum_float));
  CUDA_SAFE_CALL(cudaFree(d_buf));
}
